    c_id = clean_id(c['id'])
    owner_id = clean_id(c['ownerid'])
    closed = parse_date(c['closeddate'])
    created = parse_date(c['createddate'])

    if closed and created and start_date <= closed <= end_date:
        relevant_cases.append({
            'id': c_id,
            'ownerid': owner_id,
            'duration': (closed - created).total_seconds(),
            'created': created,
            'closed': closed
        })
        relevant_case_ids.add(c_id)

# Process History
case_history_map = {} # case_id -> list of entries
for h in history:
    cid = clean_id(h['caseid__c'])
    if cid in relevant_case_ids:
        if cid not in case_history_map:
            case_history_map[cid] = []
        case_history_map[cid].append({
            'old': clean_id(h['oldvalue__c']),
            'new': clean_id(h['newvalue__c'])
        })

# Agent Stats
agent_counts = {} # AgentId -> set of case_ids
agent_handle_times = {} # AgentId -> list of durations

for c in relevant_cases:
    cid = c['id']
    hist_entries = case_history_map.get(cid, [])

    # Determine Transfer
    # Condition: > 1 Owner Assignment entry
    # My history list only contains entries where field__c='Owner Assignment' (from query)
    is_transferred = len(hist_entries) > 1

    # Identify Agents
    involved_agents = set()
    involved_agents.add(c['ownerid']) # Current owner
    for h in hist_entries:
        if h['new'] and h['new'] != 'None':
            involved_agents.add(h['new'])
        if h['old'] and h['old'] != 'None':
            involved_agents.add(h['old'])

    # Update Counts
    for ag in involved_agents:
        if ag not in agent_counts:
            agent_counts[ag] = set()
        agent_counts[ag].add(cid)

    # Update Handle Time (only if not transferred)
    if not is_transferred:
        # Only the current owner gets credit
        # And since not transferred, current owner should be the only one (or the one in the single history entry)
        owner = c['ownerid']
        if owner not in agent_handle_times:
            agent_handle_times[owner] = []
        agent_handle_times[owner].append(c['duration'])

# Calculate Results
results = []
for agent, cases_set in agent_counts.items():
    count = len(cases_set)
    if count > 1:
        times = agent_handle_times.get(agent, [])
        if times:
            avg_time = sum(times) / len(times)
            results.append({'agent': agent, 'avg_time': avg_time, 'count': count})

# Find Lowest
if results:
    best = min(results, key=lambda x: x['avg_time'])
    print("__RESULT__:")
    print(json.dumps(best['agent']))
else:
    print("__RESULT__:")
    print(json.dumps("No matching agent found"))
