    created = parse_date(c['createddate'])
    closed = parse_date(c['closeddate'])
    owner_id = clean_id(c['ownerid'])

    # 1. Determine if Active in Window (for Count)
    # Created <= End and (Closed is None or Closed >= Start)
    is_active = False
    if created and created <= end_date:
